#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m,a[502][502],tot=0;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            a[i][j]=++tot;
    for(int i=1;i<=m;i++){
        int x,y,r,z,b[502][502];
        scanf("%d%d%d%d",&x,&y,&r,&z);
        for(int i=x-r;i<=x+r;i++)
            for(int j=y-r;j<=y+r;j++){
                int u=x+(j-y),v=y+(i-x);
                if(z==0)
                    v=y+(y-v);
                else
                    u=x+(x-u);
                b[u][v]=a[i][j];
            }
        for(int i=x-r;i<=x+r;i++)
            for(int j=y-r;j<=y+r;j++)
                a[i][j]=b[i][j];
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++)
            printf("%d ",a[i][j]);
        printf("\n");
    }
    return 0;
}
